Here's how to structure your tests using modern MSTest patterns:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler("hello world", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act
        var result = await fetcher.FetchAsync("https://example.com");

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        var handler = new FakeHttpMessageHandler("", HttpStatusCode.NotFound);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com/missing"));
    }

    [TestMethod]
    [Timeout(5000)] // safety net — test fails if it hangs
    public async Task FetchAsync_WithTimeout_CompletesInTime()
    {
        var handler = new FakeHttpMessageHandler("fast", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Pass TestContext.CancellationToken so [Timeout] can cancel cooperatively
        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        Assert.AreEqual("fast", result);
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsTaskCanceledException()
    {
        var handler = new FakeHttpMessageHandler("data", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(10));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();

        // Cancel immediately
        cts.Cancel();

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }
}
```

And the fake handler to avoid real HTTP calls:

```csharp
internal sealed class FakeHttpMessageHandler : HttpMessageHandler
{
    private readonly string _content;
    private readonly HttpStatusCode _statusCode;
    private readonly TimeSpan _delay;

    public FakeHttpMessageHandler(string content, HttpStatusCode statusCode, TimeSpan delay = default)
    {
        _content = content;
        _statusCode = statusCode;
        _delay = delay;
    }

    protected override async Task<HttpResponseMessage> SendAsync(
        HttpRequestMessage request, CancellationToken cancellationToken)
    {
        if (_delay > TimeSpan.Zero)
            await Task.Delay(_delay, cancellationToken);

        return new HttpResponseMessage(_statusCode)
        {
            Content = new StringContent(_content)
        };
    }
}
```

**Key takeaways:**

| Pattern | Why |
|---|---|
| `TestContext` via constructor | Enables `readonly`, satisfies nullability |
| `[Timeout(5000)]` + `_testContext.CancellationToken` | Cooperative cancellation — `[Timeout]` fires the token so the test stops cleanly instead of hanging |
| `Assert.ThrowsExactlyAsync<T>` | Replaces `[ExpectedException]` — lets you inspect the exception and won't swallow unexpected throws |
| `sealed` test class | Performance and design clarity |
| Fake `HttpMessageHandler` | Avoids real network calls; the `delay` + `cancellationToken` in `SendAsync` makes cancellation tests deterministic |
